import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.BPmc_f4o.js";const h=JSON.parse('{"title":"Emails","description":"","frontmatter":{},"headers":[],"relativePath":"mails/mails.md","filePath":"mails/mails.md"}'),n={name:"mails/mails.md"};function o(r,e,l,d,p,m){return t(),i("div",null,[...e[0]||(e[0]=[s('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="emails" tabindex="-1">Emails <a class="header-anchor" href="#emails" aria-label="Permalink to &quot;Emails&quot;">​</a></h1><p>Email templates define reusable transactional messages fired by <a href="/automations/automations.html">Automations</a>. Emails are a Pro feature and do not exist in the free tier.</p><hr><h2 id="emails-list" tabindex="-1">Emails List <a class="header-anchor" href="#emails-list" aria-label="Permalink to &quot;Emails List&quot;">​</a></h2><p>The default view is the emails list. It follows the same pattern as other entry lists in the plugin:</p><ul><li><strong>Add</strong> a new template with the add button.</li><li><strong>Enable / Disable</strong> an entry with the toggle. A confirmation is required.</li><li><strong>Delete</strong> an entry. A confirmation is required.</li></ul><hr><h2 id="email-editor" tabindex="-1">Email Editor <a class="header-anchor" href="#email-editor" aria-label="Permalink to &quot;Email Editor&quot;">​</a></h2><ul><li><strong>Title</strong> — display name used in the admin list.</li><li><strong>Description</strong> — internal notes, not sent to recipients.</li><li><strong>To</strong> — recipient email address.</li><li><strong>CC</strong> — carbon copy recipients.</li><li><strong>BCC</strong> — blind carbon copy recipients.</li><li><strong>Subject</strong> — email subject line.</li><li><strong>Body</strong> — HTML email content. A full payload mapping system — allowing automation event data to be referenced as placeholders in the subject and body — is coming soon.</li></ul><hr><h2 id="smtp-settings" tabindex="-1">SMTP Settings <a class="header-anchor" href="#smtp-settings" aria-label="Permalink to &quot;SMTP Settings&quot;">​</a></h2><p>The second tab in the panel is SMTP configuration. Like all settings in Pro, SMTP is scoped per application — each application can use a different sender identity and mail server.</p><p>Configurable fields: SMTP host, port, encryption, username, password, and sender name / address. If SMTP is disabled, WordPress <code>wp_mail()</code> is used as fallback.</p><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>How are emails triggered?</strong></p><p>Emails are fired by automations. Create an automation, configure its event and conditions, then add a <em>Send Email</em> action pointing to a template.</p><p><strong>Can I send to multiple recipients?</strong></p><p>Yes. Fill in To, CC, and BCC as needed. Multiple addresses in the same field can be comma-separated.</p><p><strong>Are sent emails logged?</strong></p><p>Sent emails are recorded in the application log with timestamp, recipient, and delivery status.</p>',22)])])}const g=a(n,[["render",o]]);export{h as __pageData,g as default};
